sql:
SELECT m.tournament_id, m.group_id, SUM(m.attendance) AS total_attendance
FROM matches m
GROUP BY m.tournament_id, m.group_id;

SELECT match_id, attendance 
FROM matches 
WHERE attendance < (SELECT AVG(attendance) FROM matches);

SELECT t.team_name, g.group_name
FROM teams t
JOIN groups g ON t.group_id = g.group_id;

external_knowledge:
- 'sailed through the initial sea of competition' metaphorically refers to matches in the 'group stage';
- 'voyage identifiers' refers to the unique match IDs;
- 'group waters' refers to group IDs;
- 'size of the waves they have weathered' refers to the scores of the teams, indicating the intensity of the matches, with higher scores being more 'stormy'.

